添加必要的计算引擎
----
--包含DDL、DML、DQL、raise notice以及游标，其中DQL语句涉及简单查询和复杂查询，匿名代码段，包含入参和出参
-- 如果存储过程已经存在，先删除它
IF OBJECT_ID(&#039;dbo.GetEmployeeDetails_001&#039;, &#039;P&#039;) IS NOT NULL
DROP PROCEDURE dbo.GetEmployeeDetails_001;
-- 创建存储过程
CREATE PROCEDURE dbo.GetEmployeeDetails_001
@InputEmployeeID INT
AS
BEGIN
-- 声明局部变量以保存员工姓名和平均薪资
DECLARE @LocalEmployeeID INT,
@simple_result VARCHAR(500),
@complex_result VARCHAR(500),
@lambda_sign DECIMAL(10, 2),
@EmployeeName VARCHAR(100),
@AvgSalary DECIMAL(10, 2);
-- DQL: 简单查询
SELECT @simple_result = FirstName + &#039; &#039; + LastName
FROM sqlserver_table
WHERE EmployeeID = @InputEmployeeID;
-- DQL: 复杂查询
set @complex_result =
(SELECT CONCAT(EmployeeID, FirstName, LastName, Salary) AS complex_result
FROM sqlserver_table
WHERE Salary &gt; (SELECT AVG(Salary) FROM sqlserver_table));
-- RAISERROR: 抛出错误信息
IF @InputEmployeeID &gt; 5
BEGIN
RAISERROR(&#039;Employee not found&#039;, 16, 1);
END
-- 匿名代码段
SELECT @AvgSalary = AVG(Salary) FROM sqlserver_table;
PRINT &#039;Average Salary: &#039; + CAST(@AvgSalary AS NVARCHAR(50));
--输出结果
SELECT @InputEmployeeID AS InputEmployeeID, @simple_result AS simple_result, @complex_result AS complex_result, @AvgSalary AS AvgSalary;
END;
